466	// Scenario 6: hub restart. We register two spokes, persist (handler
467	// already does this synchronously), then construct a brand-new Server
468	// against the same XDG state path. The new hub must (a) load the prior
469	// registry from disk on EnableHubMode, (b) accept a federated query
470	// immediately (no warm-up needed), (c) have its registry repopulated /
471	// refreshed by the next heartbeat (status moves from whatever was
472	// persisted → Active).
473	// ---------------------------------------------------------------------------
474	func testChaosHubRestartRebuildAndRepopulate(t *testing.T) {
475		// Set XDG_DATA_HOME to a stable temp dir BEFORE starting either hub
476		// so both hub instances share the same federation-state.json path.
477		xdg := t.TempDir()
478		t.Setenv("XDG_DATA_HOME", xdg)
479		statePath := filepath.Join(xdg, "ddx", "federation-state.json")
480	
481		// Spokes outlive the hub restart — they're independent processes in
482		// production, and httptest.Server is a process-local stand-in.
483		s1Spoke := newChaosSpoke(t, "n1-restart", func(w http.ResponseWriter, r *http.Request) {
484			_, _ = w.Write([]byte(`{"data":{"ok":true}}`))
485		})
486		s2Spoke := newChaosSpoke(t, "n2-restart", func(w http.ResponseWriter, r *http.Request) {
487			_, _ = w.Write([]byte(`{"data":{"ok":true}}`))
488		})
489	
490		// First hub instance — pinned to the shared XDG dir.
491		hub1 := newHubServerSharedXDG(t, xdg)
492		if r := registerVia(t, hub1, s1Spoke, "fp-n1"); r.StatusCode != http.StatusOK {
493			t.Fatalf("hub1 register n1: %d", r.StatusCode)
494		}
495		if r := registerVia(t, hub1, s2Spoke, "fp-n2"); r.StatusCode != http.StatusOK {
496			t.Fatalf("hub1 register n2: %d", r.StatusCode)
497		}
498		// Heartbeat n1 so we can later distinguish "loaded but never seen
499		// since restart" (n2: still Registered) from "refreshed by heartbeat
500		// after restart" (n1: Active again).
501		resp := federationDoRequest(t, hub1, "POST", "/api/federation/heartbeat",
502			map[string]string{"node_id": s1Spoke.rec.NodeID}, "loopback")
503		if resp.StatusCode != http.StatusOK {
504			t.Fatalf("hub1 heartbeat n1: %d", resp.StatusCode)
505		}
506	
507		// Sanity: state file was written.
508		if got := hub1.hub.statePath; got != statePath {
509			t.Fatalf("hub1 statePath = %q, want %q (XDG override not honored)", got, statePath)
510		}
511	
512		// "Crash" hub1: drop all references and stand up hub2 against the
513		// same XDG state path. EnableHubMode must rehydrate the registry
514		// from disk before the first request lands.
515		hub2 := newHubServerSharedXDG(t, xdg)
516	
517		snap := hub2.HubFederationRegistrySnapshot()
518		if snap == nil {
519			t.Fatalf("hub2 has nil snapshot after restart")
520		}
521		if len(snap.Spokes) != 2 {
522			t.Fatalf("hub2 loaded %d spokes from disk, want 2", len(snap.Spokes))
523		}
524		if snap.FindSpoke(s1Spoke.rec.NodeID) == nil || snap.FindSpoke(s2Spoke.rec.NodeID) == nil {
525			t.Fatalf("hub2 missing one of the persisted spokes; have %+v", snap.Spokes)
526		}
527	
528		// Immediate fan-out against the rebuilt registry — both spoke servers
529		// are still up, so we must get two responses.
530		c := newChaosFanOutClient(500 * time.Millisecond)
531		res, err := c.Execute(context.Background(), snap.Spokes, &federation.FanOutRequest{Query: "{ __typename }"})
532		if err != nil {
533			t.Fatalf("execute against rebuilt registry: %v", err)
534		}
535		if len(res.Responses) != 2 {
536			t.Fatalf("immediate-query responses = %d, want 2 (errors=%v)", len(res.Responses), res.Errors)
537		}
