14	// federationDoRequest is a small helper that runs a request against an
15	// httptest.NewServer wrapping s.Handler() so we exercise the real net/http
16	// stack (RemoteAddr is populated by the test server, matching production
17	// trust-gating behavior). Pass remote="loopback" for trusted, "external"
18	// for an explicitly non-loopback request.
19	func federationDoRequest(t *testing.T, s *Server, method, path string, body any, remote string) *http.Response {
20		t.Helper()
21		var buf bytes.Buffer
22		if body != nil {
23			if err := json.NewEncoder(&buf).Encode(body); err != nil {
24				t.Fatalf("encode: %v", err)
25			}
26		}
27		req := httptest.NewRequest(method, path, &buf)
28		req.Header.Set("Content-Type", "application/json")
29		switch remote {
30		case "external":
31			req.RemoteAddr = "203.0.113.1:54321"
32		default:
33			req.RemoteAddr = "127.0.0.1:54321"
34		}
35		rec := httptest.NewRecorder()
36		s.Handler().ServeHTTP(rec, req)
37		return rec.Result()
38	}
